oxy_webhelp_navlinks = {"tocId-d27248e45026":{"topics":[{"title":"Dynamic disk foreign state after domain controller recovery","shortdesc":"<p class=\"shortdesc\">During a system state recovery of a domain controller to a new virtual machine, the         status of dynamic disks appear as Foreign on the new virtual machine.<\/p>","href":"adds\/dynamic_disk_foreign_state_dc.html","attributes":{"data-id":"dynamic_disk_foreign_state_dc"},"menu":{"hasChildren":false},"tocID":"dynamic_disk_foreign_state_dc-d27248e45027","next":"dynamic_disk_foreign_state_dc-d27248e45027"},{"title":"DNS debug log file path not restored","shortdesc":"<p class=\"shortdesc\">During system state recovery of a domain controller with DNS debug logging enabled,         the custom log file path may not be valid on the recovery target, causing DNS debug logging         to revert to the default path or the DNS Service to fail if the path is         inaccessible.<\/p>","href":"adds\/dns_debug_log_path_not_restored.html","attributes":{"data-id":"dns_debug_log_path_not_restored"},"menu":{"hasChildren":false},"tocID":"dns_debug_log_path_not_restored-d27248e45049","next":"dns_debug_log_path_not_restored-d27248e45049"}]}};